const { spawnSync } = require('child_process');

const binary = item.binary || {};
const allKeys = Object.keys(binary);
const attachmentKey = allKeys.find(k => {
  const b = binary[k];
  const mime = (b.mimeType || '').toLowerCase();
  const name = (b.fileName || '').toLowerCase();
  return mime.includes('spreadsheet') || mime.includes('excel') ||
         mime.includes('openxmlformats') || name.endsWith('.xlsx');
}) || allKeys.find(k => k.startsWith('attachment_')) || allKeys[0];

if (!attachmentKey) throw new Error('No attachment found. Keys: ' + allKeys.join(', '));

const fileUuid = binary[attachmentKey].data;
const binaryStorageRoot = '/Users/priyanshupatel/nomura_tmp/n8n_binary';

const findResult = spawnSync('find', [binaryStorageRoot, '-name', fileUuid, '-type', 'f'], { encoding: 'utf8' });
const rawFilePath = (findResult.stdout || '').trim().split('\n')[0];

if (!rawFilePath) throw new Error(`Binary file UUID "${fileUuid}" not found under ${binaryStorageRoot}`);

const result = spawnSync(
  '/Users/priyanshupatel/Documents/GitHub/personal/venv/bin/python3',
  ['/Users/priyanshupatel/Documents/GitHub/personal/src/preprocessing.py', rawFilePath],
  { encoding: 'utf8', timeout: 120000 }
);

if (result.error) throw new Error('Python spawn error: ' + result.error.message);
if (result.status !== 0) throw new Error('Preprocessing failed:\n' + result.stderr);

const stdout = (result.stdout || '').trim();
let parsed;
try { parsed = JSON.parse(stdout); }
catch(e) { throw new Error('Could not parse preprocessing output:\n' + stdout); }

if (parsed.error) throw new Error('Preprocessing error: ' + parsed.error);

const triggerJson = $('Gmail Trigger').item.json;
return {
  json: {
    ...parsed,
    senderEmail: triggerJson.from?.value?.[0]?.address || triggerJson.from || '',
    originalSubject: triggerJson.subject || 'CRM Export',
  }
};

const { spawnSync } = require('child_process');

const cleanFilePath = item.json.clean_file_path;
if (!cleanFilePath) throw new Error('clean_file_path missing from preprocessing output');

const meta = JSON.stringify({
  total_rows_clean: item.json.total_rows_clean,
  processing_date:  item.json.processing_date,
  timestamp:        item.json.timestamp,
});

const result = spawnSync(
  '/Users/priyanshupatel/Documents/GitHub/personal/venv/bin/python3',
  ['/Users/priyanshupatel/Documents/GitHub/personal/src/formatting.py', cleanFilePath, meta],
  { encoding: 'utf8', timeout: 180000 }
);

if (result.error) throw new Error('Python spawn error: ' + result.error.message);
if (result.status !== 0) throw new Error('Formatting failed:\n' + result.stderr);

const stdout = (result.stdout || '').trim();
let parsed;
try { parsed = JSON.parse(stdout); }
catch(e) { throw new Error('Could not parse formatting output:\n' + stdout); }

if (!parsed.success) throw new Error('Formatting error: ' + (parsed.error || 'Unknown'));

return {
  json: {
    ...item.json,
    formattedFilePath: parsed.formatted_file_path,
    formattedFileName: parsed.formatted_file_path.split('/').pop(),
    formattingSuccess: parsed.success,
  }
};

